using Microsoft.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

// Train the model before building the app
var trainer = new ModelTrainingService(
    LoggerFactory.Create(b => b.AddConsole()).CreateLogger<ModelTrainingService>());
var metrics = trainer.TrainAndEvaluate();

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

